// Extraer campos relevantes y definir qué camino sigue cada evento
const body = $input.first().json.body ?? $input.first().json;
const type = body.type ?? '';

function getContent(msg = {}) {
  if (msg.text?.body) return msg.text.body;
  if (msg.image?.caption) return `[imagen] ${msg.image.caption}`;
  if (msg.image) return '[imagen]';
  if (msg.video?.caption) return `[video] ${msg.video.caption}`;
  if (msg.video) return '[video]';
  if (msg.audio) return '[audio]';
  if (msg.voice) return '[audio de voz]';
  if (msg.document?.filename) return `[documento: ${msg.document.filename}]`;
  if (msg.document) return '[documento]';
  if (msg.sticker) return '[sticker]';
  if (msg.reaction?.emoji) return `[reaccion: ${msg.reaction.emoji}]`;
  return `[${msg.type ?? 'mensaje'}]`;
}

function getMediaUrl(msg = {}) {
  return msg.audio?.link || msg.voice?.link || msg.image?.link || msg.video?.link || null;
}

function buildResult({ phone, name = '', content, timestamp, mediaUrl = null, msgType = 'text', eventType, syncChatwoot, crmPayload, dedupeKey, direction }) {
  if (!phone || !dedupeKey) {
    return [{ json: { skip: true, reason: 'sin phone o dedupeKey' } }];
  }

  return [{
    json: {
      phone,
      name,
      content,
      timestamp: timestamp || new Date().toISOString(),
      mediaUrl,
      msgType,
      eventType,
      syncChatwoot,
      crmPayload,
      dedupeKey,
      direction
    }
  }];
}

if (type === 'whatsapp.inbound_message.received') {
  const msg = body.whatsappInboundMessage ?? {};
  const wamid = msg.wamid ?? msg.id ?? '';
  return buildResult({
    phone: msg.from ?? '',
    name: msg.customerProfile?.name ?? '',
    content: getContent(msg),
    timestamp: msg.sendTime ?? msg.timestamp ?? new Date().toISOString(),
    mediaUrl: getMediaUrl(msg),
    msgType: msg.type ?? 'text',
    eventType: type,
    syncChatwoot: true,
    crmPayload: { type, whatsappInboundMessage: msg },
    dedupeKey: wamid ? `wamid:${wamid}` : '',
    direction: 'incoming'
  });
}

if (type === 'whatsapp.smb.message.echoes') {
  const msg = body.whatsappMessage ?? {};
  const wamid = msg.wamid ?? msg.id ?? '';
  return buildResult({
    phone: msg.to ?? '',
    content: getContent(msg),
    timestamp: msg.sendTime ?? msg.createTime ?? msg.timestamp ?? new Date().toISOString(),
    mediaUrl: getMediaUrl(msg),
    msgType: msg.type ?? 'text',
    eventType: type,
    syncChatwoot: false,
    crmPayload: { type, whatsappMessage: msg },
    dedupeKey: wamid ? `wamid:${wamid}` : '',
    direction: 'outgoing'
  });
}

if (type === 'whatsapp.message.updated') {
  const msg = body.whatsappMessage ?? {};
  if (msg.status !== 'sent') {
    return [{ json: { skip: true, reason: `message.updated ignorado (${msg.status ?? 'sin status'})` } }];
  }

  const wamid = msg.wamid ?? msg.id ?? '';
  return buildResult({
    phone: msg.to ?? '',
    content: getContent(msg),
    timestamp: msg.sendTime ?? msg.createTime ?? msg.timestamp ?? new Date().toISOString(),
    mediaUrl: getMediaUrl(msg),
    msgType: msg.type ?? 'text',
    eventType: type,
    syncChatwoot: false,
    crmPayload: { type, whatsappMessage: msg },
    dedupeKey: wamid ? `wamid:${wamid}` : '',
    direction: 'outgoing'
  });
}

if (type === 'whatsapp.smb.history') {
  const inbound = body.whatsappInboundMessage ?? null;
  const outbound = body.whatsappMessage ?? null;
  const msg = inbound ?? outbound ?? {};
  const phone = inbound?.from ?? outbound?.to ?? '';
  const timestamp = msg.sendTime ?? msg.createTime ?? msg.timestamp ?? new Date().toISOString();
  const wamid = msg.wamid ?? msg.id ?? '';
  const direction = inbound ? 'incoming' : 'outgoing';
  const dedupeKey = wamid || phone ? `history:${direction}:${wamid || phone}:${timestamp}` : '';

  return buildResult({
    phone,
    name: inbound?.customerProfile?.name ?? '',
    content: getContent(msg),
    timestamp,
    mediaUrl: getMediaUrl(msg),
    msgType: msg.type ?? 'text',
    eventType: type,
    syncChatwoot: false,
    crmPayload: body,
    dedupeKey,
    direction
  });
}

return [{ json: { skip: true, reason: `tipo no manejado: ${type}` } }];

// Extraer primer resultado
const data = $input.first().json;
const items = data.items ?? [];
const prospect = items[0] ?? null;
if (!prospect) {
  return [{ json: { noProspect: true } }];
}
return [{ json: { prospect } }];

const search = $input.first().json;
const contacts = search.payload ?? [];
const prospect = $('Extraer prospecto').first().json.prospect;
const phone = $('Extraer campos').first().json.phone;
const name = $('Extraer campos').first().json.name;
const content = $('Extraer campos').first().json.content;
const msgType = $('Extraer campos').first().json.msgType;

let existingContactId = null;
let existingConvId = prospect?.chatwootConversationId ?? null;

if (contacts.length > 0) {
  existingContactId = contacts[0].id;
}

return [{
  json: {
    phone,
    name,
    content,
    msgType,
    prospect,
    existingContactId,
    existingConvId: existingConvId || null,
    contactId: existingContactId,
    convId: existingConvId || null,
    needCreateContact: !existingContactId && !existingConvId,
    needLookupConversation: !!existingContactId && !existingConvId
  }
}];

const source = $input.first().json;
const createdConversation = $('Chatwoot: Crear conversación').all();
const convId = createdConversation.length > 0
  ? createdConversation[0].json.id
  : (source.convId ?? source.existingConvId ?? null);

if (!convId) {
  return [];
}

const prospect = source.prospect ?? {};
const phone = source.phone ?? $('Extraer campos').first().json.phone;
const name = source.name ?? $('Extraer campos').first().json.name;
const content = source.content ?? $('Extraer campos').first().json.content;

return [{
  json: {
    convId,
    contactId: source.contactId ?? source.existingContactId ?? null,
    prospectId: prospect.id ?? null,
    prospectPhone: phone,
    phone,
    name,
    content,
    estado: prospect.estado ?? 'enviado',
    score: prospect.oportunidadScore ?? 0,
    resumenIa: prospect.resumenIa ?? ''
  }
}];

// Etiqueta según estado CRM
const ESTADO_LABEL = {
  enviado: 'prospecto-nuevo',
  contactado: 'contactado',
  respondio: 'respondio',
  agendado: 'llamada-agendada',
  seguimiento: 'en-seguimiento',
  cerrado_positivo: 'cliente',
  cerrado_negativo: 'descartado'
};
const estado = $json.estado ?? 'enviado';
const label = ESTADO_LABEL[estado] ?? 'prospecto-nuevo';
return [{ json: { ...$json, label } }];

