// Delay aleatorio humanizado (1-4 segundos)
const delay = Math.floor(1000 + Math.random() * 3000);
await new Promise(r => setTimeout(r, delay));
return $input.all();

const source = $('Decidir Chatwoot flow').first().json;

if (source.existingConvId) {
  return [{
    json: {
      ...source,
      contactId: source.existingContactId ?? source.contactId ?? null,
      convId: source.existingConvId,
      needCreateConversation: false
    }
  }];
}

const conversations = $input.first().json.payload ?? [];
const preferredInboxId = Number($env.CHATWOOT_INBOX_ID || 0);
const sorted = [...conversations].sort((a, b) => Number(b.last_activity_at ?? b.updated_at ?? b.id ?? 0) - Number(a.last_activity_at ?? a.updated_at ?? a.id ?? 0));
const preferred = preferredInboxId ? sorted.filter((conversation) => Number(conversation.inbox_id) === preferredInboxId) : sorted;
const pool = preferred.length ? preferred : sorted;
const chosen = pool.find((conversation) => conversation.status === 'open') ?? pool[0] ?? null;

return [{
  json: {
    ...source,
    contactId: source.existingContactId ?? source.contactId ?? null,
    convId: chosen?.id ?? null,
    needCreateConversation: !chosen
  }
}];

const source = $('Decidir Chatwoot flow').first().json;
const created = $input.first().json;

return [{
  json: {
    ...source,
    contactId: created.id,
    convId: null,
    needCreateConversation: true
  }
}];

